#include <bits/stdc++.h>
using namespace std;

struct tree {
    int l, r;
    int s, lazy;
} sl[400005], sr[400005];

int n, m;

void push_up(tree t[], int p) {
    t[p].s = t[p * 2].s + t[p * 2 + 1].s;
}

void push_down(tree t[], int p) {
    t[p * 2].lazy += t[p].lazy;
    t[p * 2 + 1].lazy += t[p].lazy;
    t[p * 2].s += (t[p * 2].r - t[p * 2].l + 1) * t[p].lazy;
    t[p * 2 + 1].s += (t[p * 2 + 1].r - t[p * 2 + 1].l + 1) * t[p].lazy;
    t[p].lazy = 0;
}

void build(tree t[], int l, int r, int p) {
    t[p].l = l, t[p].r = r;
    if (l == r) return ;
    int mid = l + (r - l) / 2;
    build(t, l, mid, p * 2);
    build(t, mid + 1, r, p * 2 + 1);
}

void add(tree t[], int l, int r, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].s += t[p].r - t[p].l + 1;
        t[p].lazy++;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(t, p);
    add(t, l, r, p * 2);
    add(t, l, r, p * 2 + 1);
    push_up(t, p);
}

int query(tree t[], int k, int p) {
    if (t[p].r < k || t[p].l > k) {
        return 0;
    }
    if (t[p].l == t[p].r) {
        return t[p].s;
    }
    push_down(t, p);
    return query(t, k, p * 2) + query(t, k, p * 2 + 1);
}

int main() {
    cin >> n >> m;
    build(sl, 1, n, 1);
    build(sr, 1, n, 1);
    while (m--) {
        int q, l, r;
        cin >> q >> l >> r;
        if (q == 1) {
            add(sl, l, n, 1);
            add(sr, r, n, 1);
        }
        else {
            cout << query(sl, r, 1) - query(sr, l - 1, 1) << endl;
        }
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct tree {
    int l, r;
    ll sum;
    ll add, mul;
} t[400005];

int n, mod, m;
ll a[100005];

void push_up(int p) {
    t[p].sum = (t[p * 2].sum + t[p * 2 + 1].sum) % mod;
}

void push_down(int p) {
    t[p * 2].mul = t[p * 2].mul * t[p].mul % mod;
    t[p * 2 + 1].mul = t[p * 2 + 1].mul * t[p].mul % mod;
    t[p * 2].add = (t[p * 2].add * t[p].mul + t[p].add) % mod;
    t[p * 2 + 1].add = (t[p * 2 + 1].add * t[p].mul + t[p].add) % mod;
    t[p * 2].sum = (
        t[p * 2].sum * t[p].mul + 
        t[p].add * (t[p * 2].r - t[p * 2].l + 1)
    ) % mod;
    t[p * 2 + 1].sum = (
        t[p * 2 + 1].sum * t[p].mul + 
        t[p].add * (t[p * 2 + 1].r - t[p * 2 + 1].l + 1)
    ) % mod;
    t[p].add = 0, t[p].mul = 1;
}

void build(int l, int r, int p) {
    t[p].l = l, t[p].r = r;
    t[p].add = 0, t[p].mul = 1;
    if (l == r) {
        t[p].sum = a[l];
        return ;
    }
    int mid = l + (r - l) / 2;
    build(l, mid, p * 2);
    build(mid + 1, r, p * 2 + 1);
    push_up(p);
}

void add(int l, int r, ll x, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].sum = (t[p].sum + (t[p].r - t[p].l + 1) * x) % mod;
        t[p].add = (t[p].add + x) % mod;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(p);
    add(l, r, x, p * 2);
    add(l, r, x, p * 2 + 1);
    push_up(p);
}

void mul(int l, int r, ll x, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        t[p].sum = t[p].sum * x % mod;
        t[p].add = t[p].add * x % mod;
        t[p].mul = t[p].mul * x % mod;
        return ;
    }
    if (t[p].r < l || t[p].l > r) {
        return ;
    }
    push_down(p);
    mul(l, r, x, p * 2);
    mul(l, r, x, p * 2 + 1);
    push_up(p);
}

ll query(int l, int r, int p) {
    if (l <= t[p].l && t[p].r <= r) {
        return t[p].sum;
    }
    if (t[p].r < l || t[p].l > r) {
        return 0;
    }
    push_down(p);
    return (query(l, r, 2 * p) + query(l, r, 2 * p + 1)) % mod;
}

int main() {
    cin >> n >> mod;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    cin >> m;
    build(1, n, 1);
    while (m--) {
        int op;
        int t, g, c;
        cin >> op;
        switch (op) {
            case 1:
                cin >> t >> g >> c;
                mul(t, g, c, 1);
                break;
            case 2:
                cin >> t >> g >> c;
                add(t, g, c, 1);
                break;
            case 3:
                cin >> t >> g;
                cout << query(t, g, 1) << endl;
                break;
        }
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int n, q, f[105][105];
bool vis[105];
vector<pair<int, int> > m[105];

int DFS(int k) {
    vis[k] = true;
    if (m[k].size() == 1) 
        return 1;
    int branch = 0;
    int l = 0, r = 0, l_apple = 0, r_apple = 0;
    for (auto i : m[k]) {
        int son = i.first;
        int apple = i.second;
        if (vis[son]) 
            continue;
        if (!l) {
            l = son;
            l_apple = apple;
        }
        else {
            r = son;
            r_apple = apple;
        }
        branch += DFS(son);
    }

    for(int i = 1; i <= branch; i++){ //遍历该节点所有子树枝数量
        for(int j = 0; j <= i; j++){
            int lb = j - 1;
            int rb = i - j - 1;
            if(j == 0){ //左子节点不分配树枝
                f[k][i] = max(
                    f[k][i], 
                    f[r][rb] + r_apple
                ); //注意i-1，剪掉连接子节点1根树枝
            }
            else if(j == i){ //右子节点不分配树枝
                f[k][i] = max(
                    f[k][i], 
                    f[l][lb] + l_apple
                );
            }
            else {
                f[k][i] = max(
                    f[k][i], 
                    f[l][lb] + f[r][rb] + l_apple + r_apple
                );
            }
        }
    }
    return branch + 1;
}

int main() {
    cin >> n >> q;
    for (int i = 0; i < n - 1; i++) {
        int a, b, c;
        cin >> a >> b >> c;
        m[a].push_back(make_pair(b, c));
        m[b].push_back(make_pair(a, c));
    }
    DFS(1);
    cout << f[1][q];
    return 0;
}

#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct node {
    int next, to, w;
} e[100005];

int n, m, b, cnt = 0;
int f[50005], head[50005];
ll dis[50005];
bool vis[50005];
priority_queue<pair<ll, int>, vector<pair<ll, int> >, greater<pair<ll, int> > > q;

void add(int u, int v, int w) {
    e[++cnt].next = head[u];
    e[cnt].to = v;
    e[cnt].w = w;
    head[u] = cnt;
}

int dijkstra(int c) {
    memset(vis, 0, sizeof(vis));
    memset(dis, 0x3f, sizeof(dis));
    dis[1] = 0;
    q.push({0, 1});
    while (!q.empty()) {
        pair<ll, int> t = q.top();
        q.pop();
        int x = t.second;
        if (vis[x]) continue;
        if (x == n) break;
        vis[x] = true;
        for (int i = head[x]; i != 0; i = e[i].next) {
            int y = e[i].to;
            if (f[y] > c) continue;
            if (dis[y] > dis[x] + e[i].w) {
                dis[y] = dis[x] + e[i].w;
                q.push({dis[y], y});
            }
        }
    }
    return dis[n];
}

int main() {
    cin >> n >> m >> b;
    int l = 0, r = 0;
    for (int i = 1; i <= n; i++) {
        cin >> f[i];
        r = max(f[i], r);
    }
    l = max(f[1], f[n]);
    int x, y, z;
    for (int i = 1; i <= m; i++) {
        cin >> x >> y >> z;
        add(x, y, z);
        add(y, x, z);
    }
    int ans = 0;
    while (l <= r) {
        int m = l + (r - l) / 2;
        if (dijkstra(m) <= b) {
            ans = m;
            r = m - 1;
        }
        else {
            l = m + 1;
        }
    }
    if (dijkstra(ans) > b) {
        cout << "AFK\n";
    }
    else {
        cout << ans << endl;
    }
    return 0;
}

