typedef long long ll;

const int mod = 1e9;
int n, d[100005];
ll fct[100005];
ll p[100005], s[100005];

int main() {
    cin >> n;
    fct[0] = 1;
    for (int i = 1; i < n; i++) {
        fct[i] = fct[i - 1] * i % mod;
    }
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        cin >> u >> v;
        d[u]++, d[v]++;
    }
    p[0] = 1;
    for (int i = 1; i <= n; i++) {
        p[i] = p[i - 1] * fct[d[i] - 1] % mod;
    }
    s[n + 1] = 1;
    for (int i = n; i >= 1; i--) {
        s[i] = s[i + 1] * fct[d[i] - 1] % mod;
    }
    ll ans = 0;
    for (int i = 1; i <= n; i++) {
        ans += fct[d[i]] * p[i - 1] * s[i + 1];
    }
    cout << ans;
	return 0;
}

