const int MAX = 1e6 + 5;
struct node {
    int x, l;
    const bool operator<(const node &x) const {
        return (this -> l) > x.l;
    }
};
int n, m;
int f[MAX], cnt[MAX];
bool v[MAX];
vector<int> e[MAX];
priority_queue<node> q;

int main() {
    memset(f, 0x3f, sizeof(f));
    scanf("%d %d", &n, &m);
    for (int i = 0; i < m; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        e[x].push_back(y);
        e[y].push_back(x);
    }
    f[1] = 0, cnt[1] = 1;
    q.push(node{1, 0});
    while (!q.empty()) {
        node t = q.top();
        int x = t.x;
        q.pop();
        if (v[x]) continue;
        v[x] = true;
        for (int y : e[x]) {
            if (f[x] + 1 < f[y]) {
                f[y] = f[x] + 1;
                cnt[y] = cnt[x];
                q.push(node{y, f[y]});
            }
            else if (f[x] + 1 == f[y]) {
                cnt[y] += cnt[x];
            }
            cnt[y] %= 100003;
        }
    }
    for (int i = 1; i <= n; i++) {
        printf("%d\n", cnt[i]);
    }
    return 0;
}

