#include <bits/stdc++.h>
using namespace std;

int n, m, s;
vector<int> e[500005];
int f[500005][25];
int d[500005];

void dfs(int x, int fa) {
    d[x] = d[fa] + 1;
    f[x][0] = fa;
    for (int i = 1; i <= 20; i++) {
        f[x][i] = f[f[x][i - 1]][i - 1];
    }
    for (int y : e[x]) {
        if (y != fa) {
            dfs(y, x);
        }
    }
}

int lca(int x, int y) {
    if (d[y] > d[x]) swap(x, y);
    for (int i = 20; i >= 0; i--) {
        if (d[f[x][i]] >= d[y]) {
            x = f[x][i];
        }
    }
    if (x == y) return x;
    for (int i = 20; i >= 0; i--) {
        if (f[x][i] != f[y][i]) {
            x = f[x][i];
            y = f[y][i];
        }
    }
    return f[x][0];
}

int main() {
    scanf("%d %d %d", &n, &m, &s);
    for (int i = 0; i < n - 1; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        e[a].push_back(b);
        e[b].push_back(a);
    }
    dfs(s, 0);
    while (m--) {
        int a, b;
        scanf("%d %d", &a, &b);
        printf("%d\n", lca(a, b));
    }
    return 0;
}

