int n, k, l[100005], maxn = INT_MIN;

bool check(int x) {
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        cnt += l[i] / x;
    }
    return (cnt >= k);
}

int find() {
    int l = 0, r = maxn;
    int mid = (l + r + 1) >> 1;
