#include <bits/stdc++.h>
using namespace std;

struct tree {
    int l, r;
    int cnt;
} t[400005];

int n;
int a[100005], b[100005];
int mp[100005];

void push_up(int p) {
    t[p].cnt = t[p * 2].cnt + t[p * 2 + 1].cnt;
}

void build(int l, int r, int p) {
    t[p].l = l, t[p].r = r;
    if (l == r) return ;
    int mid = l + (r - l) / 2;
    build(l, mid, p * 2);
    build(mid + 1, r, p * 2 + 1);
    push_up(p);
}

void update(int k, int p) {
    if (t[p].r < k || t[p].l > k) {
        return ;
    }
    if (t[p].l == t[p].r) {
        t[p].cnt++;
        return ;
    }
    update(k, 2 * p);
    update(k, 2 * p + 1);
    push_up(p);
}

int query(int k, int p) {
    if (t[p].l == t[p].r) {
        return t[p].l;
    }
    if (k <= t[p * 2].cnt) {
        return query(k, p * 2);
    }
    else {
        return query(k - t[p * 2].cnt, p * 2 + 1);
    }
}

