    for (int i = 1; i <= n; i++) {
        int x = lower_bound(b + 1, b + 1 + n, a[i]) - b;
        mp[x] = a[i];
        a[i] = x;
    }
    build(1, m, 1);
    for (int i = 1; i <= n; i++) {
        update(a[i], 1);
        if (i % 2 == 1) {
            cout << mp[query(i / 2 + 1, 1)] << endl;
        }
    }
    return 0;
}

