const int MAXN = 2005;
struct big_num {
    int numbers[MAXN];
    int len;
    big_num() {
        len = 0;
        memset(this -> numbers, 0, sizeof(this -> numbers));
    }
    big_num(int l) {
        len = l;
        memset(this -> numbers, 0, sizeof(int) * (l + 5));
    }
    big_num(int l, int x) {
        len = l;
        memset(this -> numbers, 0, sizeof(int) * (l + 5));
        this -> numbers[0] = x;
    }
    big_num(string s) {
        this -> len = s.size();
        for (int i = 0; i < this -> len; i++)
            this -> numbers[i] = s[this -> len - i - 1] - '0';
    }
    big_num operator+(const big_num &b) {
        big_num ans;
        ans = big_num(max(this -> len, b.len));
        for (int i = 0; i < ans.len; i++) {
            ans.numbers[i] += this -> numbers[i] + b.numbers[i];
            if (ans.numbers[i] > 9) {
                ans.numbers[i + 1]++;
                ans.numbers[i] -= 10;
                if (i == ans.len - 1) {
