} stu[3005];

bool cmp(student a, student b) {
    if (a.h == b.h)
        return a.w >= b.w;
    return a.h > b.h;
}

void merge_sort(student a[], int l, int r) {
    if (l == r) return ;
    int mid = (l + r) >> 1;
    merge_sort(a, l, mid);
    merge_sort(a, mid + 1, r);
    int i = l, j = mid + 1, k = l;
    student tmp[3005];
    while (i <= mid && j <= r) {
        if (cmp(a[i], a[j]))
            tmp[k++] = a[i++];
        else {
            tmp[k++] = a[j++];
            cnt += mid - i + 1;
        }
    }
    while (i <= mid) 
        tmp[k++] = a[i++];
    while (j <= r)
        tmp[k++] = a[j++];
    for (int i = l; i <= r; i++) 
        a[i] = tmp[i];
}

