#include <bits/stdc++.h>
using namespace std;

struct student {
    int number;
    int c, m, e;
    int sum, cm_sum, cm_max;
} stu[10005];

bool is_par(student a, student b) {
    if (a.sum == b.sum)
        if (a.cm_sum == b.cm_sum)
            if (a.cm_max == b.cm_max)
                return true;
    return false;
}

bool cmp(student a, student b) {
    if (a.sum == b.sum) {
        if (a.cm_sum == b.cm_sum) {
            if (a.cm_max == b.cm_max) {
                return true;
            }
            return a.cm_max > b.cm_max;
        }
        return a.cm_sum > b.cm_sum;
    }
    return a.sum > b.sum;
}

int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        int ci, mi, ei;
        cin >> ci >> mi >> ei;
        stu[i].number = i;
        stu[i].c      = ci;
        stu[i].m      = mi;
        stu[i].e      = ei;
        stu[i].sum    = ci + mi + ei;
        stu[i].cm_sum = ci + mi;
        stu[i].cm_max = max(ci, mi);
    }
    sort(stu, stu + n, cmp);
    int race[10005];
    int lrace = 1;
    for (int i = 0; i < n; i++) {
        if (i != 0 && is_par(stu[i - 1], stu[i])) {
            race[stu[i].number] = lrace;
        }
        else {
            lrace = i + 1;
            race[stu[i].number] = i + 1;
        }

    }
    for (int i = 0; i < n; i++)
        cout << race[i] << endl;
    return 0;
}

