bool islog2(int a) {
    while (a > 1) {
        if ((a & 1) == 1) {
            return false;
        }
        a >>= 1;
    }
    return true;
}

int main() {
    int n;
    cin >> n;
    if ((n & 1) == 1) {
        cout << -1;
        return 0;
    }
    if (islog2(n)) {
        cout << n;
        return 0;
    }
    while (n) {
        int i;
        for (i = n; i > 1; i--) {
            if (islog2(i)) {
                cout << i << ' ';
                n -= i;
                break;
            }
        }
    }
    return 0;
}

