ll m(ll l, ll r) {
    if (abs(r - l) > 5) {
        ll tmp = ll((l + r) / 2LL);
        // ll ans=((m(l, tmp) % max(m(tmp + 1, r), ll(7))) + (a[tmp] - 1));
