struct line {
    int v, a;
    line(int x, int y) {
        this -> v = x;
        this -> a = y;
    }
};

int n, m, k, ans[10005];
vector<line> l[10005];
queue<int> q;

int main() {
    for (int i = 0; i < 10005; i++) {
        ans[i] = INT_MAX;
    }
    cin >> n >> m >> k;
    for (int i = 0; i < n; i++) {
        int u, v, a;
        cin >> u >> v >> a;
        l[u].push_back(line(v, a));
    }
    q.push(1);
    ans[1] = 0;
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        for (auto i : l[u]) {
            q.push(i.v);
            int t, t2;
            t = (i.a - ans[u]);
            if (t <= 0) t2 = ans[u] + 1;
            else t2 = ans[u] + 1 + ((t / k + (t % k != 0)) * k);
            if (i.v == n && t2 % k != 0) {
                // cout << "continue" << endl;
                continue;
            }
            ans[i.v] = min(ans[i.v], t2);
            // printf("from %d to %d value %d queue ", u, i.v, t2);
            // for (int j = 0; j < q.size(); j++) {
            //     cout << *(&q.front() + j) << " ";
            // }
            // cout << endl;
        }
    }
    cout << (ans[n] == INT_MAX ? -1 : ans[n]) << endl;
    return 0;
}

