void to_ints(string s, int it[205], int &len) {
    int l = s.size();
    while (s[0] == '0' && l > 0) {
        s.erase(s.begin());
        l--;
    }
    if (l == 0) {
        it[0] = 0;
        len = 1;
        return ;
    }
    len = 0;
    for (int i = 0; i < l; i++) {
        it[l - i - 1] = s[i] - '0';
        len++;
    }
    it[len] = 0;
}

