}

void add(int a[205], int b[205], int la, int lb, int &l) {
    l = max(la, lb);
    for (int i = 0; i < l; i++) {
        int t = a[i] + b[i];
        a[i] = t % 10;
        if (t > 9) {
            a[i + 1] += t / 10;
            if (i == l - 1) {
                l++;
            }
        }
    }
}

int main() {
