int n, a[5005];
int f1[5005];
int f2[5005];

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
    int ans = 0;
    for (int k = 1; k <= n; k++) {
        memset(f1, 0, sizeof(f1));
        memset(f2, 0, sizeof(f2));
        int tmp1 = 0, tmp2 = 0;
        for (int i = k - 1; i >= 1; i--) {
            if (a[i] >= a[k]) continue;
            f1[i] = 1;
            for (int j = i + 1; j <= k - 1; j++) {
                if (a[i] < a[j] && a[j] < a[k]) {
                    f1[i] = max(f1[i], f1[j] + 1);
                }
            }
            tmp1 = max(tmp1, f1[i]);
        }
        for (int i = k + 1; i <= n; i++) {
            if (a[k] <= a[i]) continue;
            f2[i] = 1;
            for (int j = i - 1; j >= k + 1; j--) {
                if (a[k] > a[j] && a[j] > a[i]) {
                    f2[i] = max(f2[i], f2[j] + 1);
                }
            }
            tmp2 = max(tmp2, f2[i]);
        }
        // printf("%d  %d %d\n", k, tmp1, tmp2);
        ans = max(ans, tmp1 + tmp2 + 1);
    }
    cout << ans;
    return 0;
}

